import java.util.*

fun solve(c: Long, connections: Array<Array<Long>>, queries: Array<Array<Long>>): Array<Long> {
    val nNodes = c.toInt()
    val graph = Array(nNodes + 1) { mutableListOf<Int>() }

    for (edge in connections) {
        val u = edge[0].toInt()
        val v = edge[1].toInt()
        graph[u].add(v)
        graph[v].add(u)
    }

    val visited = BooleanArray(nNodes + 1) { false }
    val comp = IntArray(nNodes + 1) { -1 }
    var compCount = 0

    for (i in 1..nNodes) {
        if (!visited[i]) {
            val queue = LinkedList<Int>()
            queue.add(i)
            visited[i] = true
            comp[i] = compCount
            while (queue.isNotEmpty()) {
                val node = queue.poll()
                for (neighbor in graph[node]) {
                    if (!visited[neighbor]) {
                        visited[neighbor] = true
                        comp[neighbor] = compCount
                        queue.add(neighbor)
                    }
                }
            }
            compCount++
        }
    }

    val compSets = Array(compCount) { TreeSet<Long>() }
    val online = BooleanArray(nNodes + 1) { true }

    for (i in 1..nNodes) {
        compSets[comp[i]].add(i.toLong())
    }

    val ans = mutableListOf<Long>()
    for (q in queries) {
        val type = q[0]
        val x = q[1]
        val idx = x.toInt()

        if (type == 1L) {
            if (online[idx]) {
                ans.add(x)
            } else {
                val cid = comp[idx]
                if (compSets[cid].isEmpty()) {
                    ans.add(-1)
                } else {
                    ans.add(compSets[cid].first())
                }
            }
        } else {
            if (online[idx]) {
                online[idx] = false
                compSets[comp[idx]].remove(x)
            }
        }
    }

    return ans.toTypedArray()
}
```

### Explanation
1. **Graph Construction**: The adjacency list `graph` is built from the input connections. Each station's neighbors are stored in a list for quick access.
2. **Component Identification**: Using BFS, each connected component is labeled with a unique component ID (`compCount`). Stations in the same component share the same ID.
3. **Component Tracking**: For each component, a `TreeSet` is used to maintain online stations in sorted order. This allows efficient minimum value retrieval and removal operations.
4. **Query Processing**:
   - For **Type 1 Queries**, the station's status is checked. If online, it returns itself; otherwise, it checks the smallest online station in its component.
   - For **Type 2 Queries**, the station is marked offline and removed from its component's `TreeSet`.
5. **Efficiency**: The BFS runs in O(V + E) time. Each query (Type 1 or Type 2) processes in O(log K) time, where K is the size of the component's sorted set, making the solution efficient for large inputs.

