fun solve(c: Long, connections: Array<Array<Long>>, queries: Array<Array<Long>>): Array<Long> {
    val nNodes = c.toInt()

    class DSU(val size: Int) {
        val parent = IntArray(size + 1) { it }
        val rank = IntArray(size + 1) { 0 }

        fun find(x: Int): Int {
            if (parent[x] != x) {
                parent[x] = find(parent[x])
            }
            return parent[x]
        }

        fun union(x: Int, y: Int) {
            val rx = find(x)
            val ry = find(y)
            if (rx == ry) return
            if (rank[rx] < rank[ry]) {
                parent[rx] = ry
            } else if (rank[rx] > rank[ry]) {
                parent[ry] = rx
            } else {
                parent[ry] = rx
                rank[rx]++
            }
        }
    }

    val dsu = DSU(nNodes)

    for (conn in connections) {
        val u = conn[0].toInt()
        val v = conn[1].toInt()
        dsu.union(u, v)
    }

    val compSets = mutableMapOf<Int, TreeSet<Int>>()
    for (i in 1..nNodes) {
        val root = dsu.find(i)
        compSets.getOrPut(root) { TreeSet() }.add(i)
    }

    val online = BooleanArray(nNodes + 1) { true }
    val resultList = mutableListOf<Long>()

    for (q in queries) {
        val type = q[0].toInt()
        val x = q[1].toInt()
        when (type) {
            1 -> {
                if (online[x]) {
                    resultList.add(x.toLong())
                } else {
                    val root = dsu.find(x)
                    val set = compSets[root]
                    if (set == null || set.isEmpty()) {
                        resultList.add(-1L)
                    } else {
                        resultList.add(set.first().toLong())
                    }
                }
            }
            2 -> {
                if (online[x]) {
                    online[x] = false
                    val root = dsu.find(x)
                    compSets[root]?.remove(x)
                }
            }
        }
    }

    return resultList.toTypedArray()
}
```

### Explanation
1. **DSU Initialization**: The DSU data structure is initialized to manage connected components. Path compression and union by rank optimizations ensure efficient operations.
2. **Component Sets**: After processing all connections, we build a map where each key is a component root, and the value is a TreeSet containing all online nodes in that component initially.
3. **Query Handling**:
   - **Type 1 Query (Maintenance Check)**: If the node is online, the result is the node itself. If offline, the smallest online node in its component is retrieved from the TreeSet. If no online nodes exist, the result is -1.
   - **Type 2 Query (Offline)**: The node's online status is updated to false, and it is removed from the corresponding TreeSet.
4. **Efficiency**: Using DSU and TreeSets ensures that both union operations and queries are handled efficiently, with near-constant time for DSU operations and logarithmic time for TreeSet operations, making the solution scalable for large inputs.
